import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  city: string;
  temp: number;
  condition: 'sunny' | 'cloudy' | 'rainy';
  humidity: number;
  wind: number;
  forecast: { day: string; icon: string; high: number; low: number }[];
}

function useComponent(props: Props) {
  const getConditionIcon = useCallback((condition: string) => {
    switch (condition) {
      case 'sunny': return '☀️';
      case 'cloudy': return '☁️';
      case 'rainy': return '🌧️';
      default: return '🌤️';
    }
  }, []);

  return { ...props, getConditionIcon };
}

export default function Component(props: Props) {
  const { city, temp, condition, humidity, wind, forecast, getConditionIcon } = useComponent(props);

  return (
    <Card padding={24} shadow="md" style={{ width: '100%', maxWidth: '320px' }}>
      <Stack gap={16} align="center">
        <Heading level={2}>{city}</Heading>
        <Text variant="bodyLarge" size="4xl" weight="bold">{temp}°</Text>
        <Text variant="body">{getConditionIcon(condition)} {condition.toUpperCase()}</Text>
        <Row style={{ width: '100%', justifyContent: 'space-around' }}>
            <Text variant="caption">Humidity: {humidity}%</Text>
            <Text variant="caption">Wind: {wind} mph</Text>
        </Row>
        <Divider margin={8} />
        <Row style={{ width: '100%', justifyContent: 'space-between' }}>
          {forecast.map((f, i) => (
            <Stack key={i} align="center" gap={4}>
              <Text variant="caption">{f.day}</Text>
              <Text>{f.icon}</Text>
              <Text variant="bodySmall">{f.high}°/{f.low}°</Text>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Badge } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Props {
  elements: {
    atomicNumber: number;
    symbol: string;
    name: string;
    atomicWeight: number;
    category: string;
    row: number;
    column: number;
  }[];
}

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    const s = search.toLowerCase();
    return props.elements.filter(e => 
      e.name.toLowerCase().includes(s) || 
      e.symbol.toLowerCase().includes(s)
    );
  }, [props.elements, search]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);

  return { search, setSearch, selected, setSelected, filtered, categories };
}

export default function Component(props: Props) {
  const { search, setSearch, selected, setSelected, filtered, categories } = useComponent(props);

  const getCategoryColor = (cat: string) => {
    const map: Record<string, string> = {
      'noble gas': 'var(--ggui-color-info-400)',
      'halogen': 'var(--ggui-color-warning-400)',
      'alkali metal': 'var(--ggui-color-error-400)',
      'alkaline earth metal': 'var(--ggui-color-success-400)',
      'transition metal': 'var(--ggui-color-primary-400)',
    };
    return map[cat] || 'var(--ggui-color-outline)';
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <SearchField value={search} onChange={setSearch} placeholder="Search elements..." />

        <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4, 16px)" borderRadius="md">
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)' }}>
            {filtered.map(e => (
              <div
                key={e.atomicNumber}
                onClick={() => setSelected(e)}
                style={{ 
                  gridRow: e.row, 
                  gridColumn: e.column, 
                  cursor: 'pointer',
                  borderColor: getCategoryColor(e.category),
                  borderWidth: '2px',
                  borderStyle: 'solid',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  backgroundColor: 'var(--ggui-color-surface, #ffffff)'
                }}
              >
                <Text variant="caption">{e.atomicNumber}</Text>
                <Heading level={5} align="center">{e.symbol}</Heading>
              </div>
            ))}
          </div>
        </Box>

        <Stack direction="horizontal" gap={8} wrap>
          {categories.map(c => (
            <Badge key={c} variant="secondary" style={{ background: getCategoryColor(c) }}>{c}</Badge>
          ))}
        </Stack>

        {selected && (
          <Card padding={24} shadow="md">
            <Heading level={2}>{selected.name} ({selected.symbol})</Heading>
            <Stack gap={8} style={{ marginTop: 16 }}>
              <Text><strong>Atomic Number:</strong> {selected.atomicNumber}</Text>
              <Text><strong>Atomic Weight:</strong> {selected.atomicWeight}</Text>
              <Text><strong>Category:</strong> {selected.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: unknown;
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: any) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    avatar: '🧑‍💻',
    role: 'Developer',
    emailNotifications: true,
    theme: 'light'
  });

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email), [formData.email]);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;

  const updateField = (field: string, value: any) => setFormData(prev => ({ ...prev, [field]: value }));

  const nextStep = () => setStep(s => Math.min(s + 1, 3));
  const prevStep = () => setStep(s => Math.max(s - 1, 1));

  const onComplete = () => {
    if (props.actions?.complete) {
      props.actions.complete(formData);
    }
  };

  return { step, formData, updateField, nextStep, prevStep, isStep1Valid, isEmailValid, onComplete };
}

export default function Component(props: Props) {
  const { step, formData, updateField, nextStep, prevStep, isStep1Valid, isEmailValid, onComplete } = useComponent(props);

  const avatars = ['🧑‍💻', '👩‍🎨', '👨‍💼', '🤖'];

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding ({step}/3)</Heading>
        <Progress value={(step - 1) * 50} max={100} />

        {step === 1 && (
          <Card padding={24}>
            <Stack gap={16}>
              <Input label="Name" value={formData.name} onChange={(v) => updateField('name', v)} required />
              <Input label="Email" type="email" value={formData.email} onChange={(v) => updateField('email', v)} required error={formData.email && !isEmailValid ? 'Invalid email format' : undefined} />
              <Text variant="label">Avatar</Text>
              <RadioGroup direction="horizontal" value={formData.avatar} onChange={(v) => updateField('avatar', v)} options={avatars.map(a => ({ label: a, value: a }))} />
            </Stack>
          </Card>
        )}

        {step === 2 && (
          <Card padding={24}>
            <Stack gap={16}>
              <Select label="Role" value={formData.role} onChange={(v) => updateField('role', v)} options={['Developer', 'Designer', 'Manager', 'Other'].map(r => ({ label: r, value: r }))} />
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => updateField('theme', v ? 'dark' : 'light')} />
            </Stack>
          </Card>
        )}

        {step === 3 && (
          <Card padding={24}>
            <Stack gap={8}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
              <Text>Theme: {formData.theme}</Text>
            </Stack>
          </Card>
        )}

        <Row justify="between">
          <Button variant="ghost" onClick={prevStep} disabled={step === 1}>Go Back</Button>
          {step < 3 ? (
            <Button onClick={nextStep} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={onComplete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
